def binary_search(arr, low, high, x):
    if high >= low:
        mid = (high + low) // 2
        if arr[mid] == x: return mid
        elif arr[mid] > x: return binary_search(arr, low, mid - 1, x)
        else: return binary_search(arr, mid + 1, high, x)
    return -1

def search_matrix(mat, x):
    for i, row in enumerate(mat):
        res = binary_search(row, 0, len(row) - 1, x)
        if res != -1: return [i, res]
    return [-1, -1]

if __name__ == "__main__":
    matrix = [[1, 3, 5], [7, 9, 11]]
    print(f"Search 9: {search_matrix(matrix, 9)}")

