import bisect

def search_matrix(mat, x):
    for i, row in enumerate(mat):
        idx = bisect.bisect_left(row, x)
        if idx < len(row) and row[idx] == x:
            return [i, idx]
    return [-1, -1]

if __name__ == "__main__":
    matrix = [[1, 3, 5], [7, 9, 11]]
    print(f"Search 9: {search_matrix(matrix, 9)}")
